import React, { useEffect, useState } from 'react';
import { supabase } from '../supabaseClient';
import WordCloud from './WordCloud';
import { motion } from 'framer-motion';

const StatisticsPage = () => {
  const [stats, setStats] = useState({
    totalProposals: 0,
    totalSignatures: 0,
    activeCitizens: 0,
    trendingCategories: []
  });

  useEffect(() => {
    fetchStats();
  }, []);

  const fetchStats = async () => {
    const { count: totalProposals } = await supabase
      .from('proposals')
      .select('*', { count: 'exact', head: true });

    const { count: totalSignatures } = await supabase
      .from('signatures')
      .select('*', { count: 'exact', head: true });

    const { count: activeCitizens } = await supabase
      .from('profiles')
      .select('*', { count: 'exact', head: true });

    setStats({
      totalProposals: totalProposals || 0,
      totalSignatures: totalSignatures || 0,
      activeCitizens: activeCitizens || 0,
      trendingCategories: [
        { name: 'Gouvernance', count: 45 },
        { name: 'Justice', count: 38 },
        { name: 'Élections', count: 52 },
        { name: 'Décentralisation', count: 29 },
        { name: 'Droits humains', count: 41 }
      ]
    });
  };

  return (
    <motion.div
      className="statistics-page"
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      transition={{ duration: 0.5 }}
    >
      <div className="stats-header">
        <h1>Tableau de bord analytique</h1>
        <p>Analyse sémantique des contributions citoyennes</p>
      </div>

      <div className="stats-grid">
        <div className="stat-card">
          <div className="stat-value">{stats.totalProposals}</div>
          <div className="stat-label">Propositions soumises</div>
        </div>
        <div className="stat-card">
          <div className="stat-value">{stats.totalSignatures}</div>
          <div className="stat-label">Signatures totales</div>
        </div>
        <div className="stat-card">
          <div className="stat-value">{stats.activeCitizens}</div>
          <div className="stat-label">Citoyens actifs</div>
        </div>
      </div>

      <div className="trending-section">
        <h3>Thèmes tendances de la semaine</h3>
        <div className="trending-bars">
          {stats.trendingCategories.map(cat => (
            <div key={cat.name} className="trending-bar">
              <span className="trending-name">{cat.name}</span>
              <div className="bar-container">
                <div className="bar-fill" style={{ width: `${(cat.count / 60) * 100}%` }} />
              </div>
              <span className="trending-count">{cat.count}</span>
            </div>
          ))}
        </div>
      </div>

      <WordCloud />
    </motion.div>
  );
};

export default StatisticsPage;
